mapper.select:
SELECT COALESCE(monthly.monthOrderCount, 0) AS monthOrderCount, COALESCE(monthly.monthOriginalWeight, 0) AS monthOriginalWeight, COALESCE(monthly.monthFinishWeight, 0) AS monthFinishWeight, COALESCE(monthly.monthAmount, 0) AS monthAmount, COALESCE(monthly.monthLossWeight, 0) AS monthLossWeight, CASE WHEN COALESCE(monthly.monthOriginalWeight, 0) = 0 THEN 0 ELSE ROUND(monthly.monthLossWeight / monthly.monthOriginalWeight * 100, 2) END AS monthLossRatio, COALESCE(stock.inStockFinishCount, 0) AS inStockFinishCount, COALESCE(stock.inStockFinishWeight, 0) AS inStockFinishWeight, COALESCE(receivable.receivableCount, 0) AS receivableCount, COALESCE(receivable.receivableAmount, 0) AS receivableAmount, COALESCE(receivable.pendingSettleAmount, 0) AS pendingSettleAmount FROM ( SELECT COUNT(*) AS monthOrderCount, COALESCE(SUM(orig.originalWeight), 0) AS monthOriginalWeight, COALESCE(SUM(fin.finishWeight), 0) AS monthFinishWeight, COALESCE(SUM(COALESCE(settle.billedAmount, o.total_amount, 0)), 0) AS monthAmount, COALESCE(SUM(orig.lossWeight), 0) AS monthLossWeight FROM biz_process_order o LEFT JOIN ( SELECT order_uuid, SUM(COALESCE(actual_weight, total_weight, roll_weight, 0)) AS originalWeight, SUM(COALESCE(total_loss_weight, 0)) AS lossWeight FROM biz_original_roll WHERE is_deleted = 0 GROUP BY order_uuid ) orig ON orig.order_uuid = o.uuid LEFT JOIN ( SELECT order_uuid, SUM(COALESCE(actual_weight, estimate_weight, 0)) AS finishWeight FROM biz_finish_roll WHERE is_deleted = 0 AND COALESCE(is_spare, 0) = 0 AND COALESCE(roll_no_status, 1) != 3 GROUP BY order_uuid ) fin ON fin.order_uuid = o.uuid LEFT JOIN (
) settle ON settle.order_uuid = o.uuid WHERE o.is_deleted = 0 AND o.order_status >= 4 AND o.order_date >= #{monthStart} AND o.order_date <= #{today} ) monthly CROSS JOIN ( SELECT COUNT(*) AS inStockFinishCount, COALESCE(SUM(COALESCE(actual_weight, estimate_weight, 0)), 0) AS inStockFinishWeight FROM biz_finish_roll WHERE is_deleted = 0 AND COALESCE(is_spare, 0) = 0 AND COALESCE(roll_no_status, 1) != 3 AND finish_status = 2 ) stock CROSS JOIN ( SELECT SUM(CASE WHEN settle.order_uuid IS NOT NULL AND GREATEST(COALESCE(settle.billedAmount, 0) - COALESCE(settle.receivedAmount, 0), 0) > 0 THEN 1 ELSE 0 END) AS receivableCount, COALESCE(SUM(GREATEST(COALESCE(settle.billedAmount, 0) - COALESCE(settle.receivedAmount, 0), 0)), 0) AS receivableAmount, COALESCE(SUM(CASE WHEN settle.order_uuid IS NULL THEN COALESCE(o.total_amount, 0) ELSE 0 END), 0) AS pendingSettleAmount FROM biz_process_order o LEFT JOIN (
) settle ON settle.order_uuid = o.uuid WHERE o.is_deleted = 0 AND o.order_status >= 4 ) receivable
